package com.interview.incidentrca.service;
import com.interview.incidentrca.entity.*;import com.interview.incidentrca.enums.*;import com.interview.incidentrca.repository.IncidentRepository;import org.junit.jupiter.api.Test;import java.time.Instant;import java.util.List;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.Mockito.*;
class DuplicateDetectionServiceTest{@Test void findsSimilarOpenIncidents(){var repo=mock(IncidentRepository.class);var svc=new DuplicateDetectionService(repo);var comp=ServiceComponent.builder().name("Payment Gateway").build();var a=Incident.builder().id(1L).title("Payment API timeout").description("database connection timeout").serviceComponent(comp).status(IncidentStatus.OPEN).createdAt(Instant.now()).build();var b=Incident.builder().id(2L).title("Payment timeout issue").description("database connection failing").serviceComponent(comp).status(IncidentStatus.OPEN).createdAt(Instant.now()).build();when(repo.findByStatusIn(any())).thenReturn(List.of(a,b));assertThat(svc.findDuplicates(a)).extracting("incidentId").contains(2L);}}
